import{_ as o,c as r,o as i,ah as t}from"./chunks/framework.C-x9UAyH.js";const c="/kotlin_estructura.png",a="/kotlin_inicio_proyecto.png",l="/kotlin_configurar_proyecto.png",g=JSON.parse('{"title":"Estructura e Inicio del proyecto","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"kotlin/estructura_proyecto.md","filePath":"kotlin/estructura_proyecto.md","lastUpdated":1760649277000}'),n={name:"kotlin/estructura_proyecto.md"};function d(s,e,p,u,_,m){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="estructura-e-inicio-del-proyecto" tabindex="-1">Estructura e Inicio del proyecto <a class="header-anchor" href="#estructura-e-inicio-del-proyecto" aria-label="Permalink to &quot;Estructura e Inicio del proyecto&quot;">​</a></h1><p>En Android Studio, cada proyecto incluye uno o más módulos con archivos de código fuente y archivos de recursos. Entre ellos se incluyen:</p><ul><li>Módulos de apps para Android</li><li>Módulos de biblioteca</li><li>Módulos de Google App Engine</li></ul><br><p align="center"><img src="'+c+'" width="500" alt="kt_estructura"></p><br><div class="tip custom-block"><p class="custom-block-title">Directorios principales del proyecto Android</p><ul><li><code>manifests/</code> → Contiene el archivo <code>AndroidManifest.xml</code></li><li><code>java/</code> → Contiene el código fuente Kotlin/Java</li><li><code>res/</code> → Contiene recursos como imágenes y cadenas</li></ul></div><h2 id="iniciar-un-proyecto" tabindex="-1">Iniciar un proyecto <a class="header-anchor" href="#iniciar-un-proyecto" aria-label="Permalink to &quot;Iniciar un proyecto&quot;">​</a></h2><ol><li><p>Primero hacer clic en <code>Start a new Android Studio project</code> para crear un proyecto nuevo en la pantalla de bienvenida de Android Studio.</p></li><li><p>En la pantalla <code>New Project</code> que aparece, se puede seleccionar el tipo de proyecto que se desee crear entre las categorías de factores de forma del dispositivo que se muestran en el panel Templates. Una vez seleccionado el tipo de proyecto que se quiere crear, Android Studio puede incluir código de muestra y recursos en el proyecto como ayuda para comenzar.</p></li><li><p>Luego de seleccionar el tipo de proyecto, hacer clic en <code>Next</code>.</p></li></ol><br><p align="center"><img src="'+a+'" width="800" alt="kt_inicio_proyecto"></p><h2 id="configurar-el-proyecto" tabindex="-1">Configurar el proyecto <a class="header-anchor" href="#configurar-el-proyecto" aria-label="Permalink to &quot;Configurar el proyecto&quot;">​</a></h2><ul><li>Especificar el nombre del proyecto</li><li>Nombre del paquete</li><li>Ruta local donde guardar el proyecto</li><li>Lenguaje: Kotlin DLS</li><li>Mínimo SDK: Lollipop API 21 - Android 5.0</li><li>Hacer click en <strong>Finish</strong></li></ul><br><p align="center"><img src="'+l+'" width="800" alt="kt_configurar_proyecto"></p>',15)])])}const h=o(n,[["render",d]]);export{g as __pageData,h as default};
